```
interface IAwardData {
    AwardType?: (number|null);
    Symbol?: (number|null);
    Count?: (number|null);
    Line?: (number|null);
    Win?: (number|null);
    Multiplier?: (number|null);
    JackpotWin?: (number|null);  // <-- This field exists!
```

